#!/bin/bash
# QDG Per-Model Pipeline: Similarity -> Clustering -> Analysis
#
# Reproduces all per-model results for a given Pythia model.
# Publication figures need BOTH models and are generated by run_cross_model.sh.
#
# Usage:
#   bash run_full_pipeline.sh              # default: pythia-19m
#   bash run_full_pipeline.sh pythia-125m
#
# Prerequisites:
#   - A machine with a GPU (V100/A100 or equivalent) and ~32 GB RAM
#   - Data and token indices (see REPRODUCE.md)
#
# Run pythia-19m first, then pythia-125m, then:
#   bash run_cross_model.sh
# to generate the cross-model taxonomy mirror and all publication figures.
#
# Approximate wall-times on a single V100 (per model):
#   step 01: ~4 h (19m) / ~35 h (125m)   step 02: ~4-6 h   step 07a: ~25 h (50 iterations)

set -e

# Require QDG_ENV to be set explicitly - prevents silently using UCloud paths
# on a local machine.  Export it before running:
#   QDG_ENV=ucloud bash run_full_pipeline.sh          (UCloud / HPC)
#   QDG_ENV=local  bash run_full_pipeline.sh          (local machine)
: "${QDG_ENV:?QDG_ENV is not set. Export QDG_ENV=ucloud or QDG_ENV=local before running.}"
export QDG_ENV

MODEL=${1:-pythia-19m}
export QDG_MODEL=$MODEL

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
cd "$SCRIPT_DIR"

echo "QDG Pipeline: $MODEL (started $(date))"
echo "  (9 steps total)"
python -c "from config import PATHS; print(f'  Results: {PATHS[\"results_dir\"]}')"

echo ""
echo "Step 1/9: Similarity matrix computation - $(date)"
# QDG_NTOKENS lets a smoke run use fewer tokens (e.g. QDG_NTOKENS=2000); unset = full 10000
python -u pipeline/01_similarity_matrix.py ${QDG_NTOKENS:+--n-tokens $QDG_NTOKENS}

echo ""
echo "Step 2/9: Clustering (Spectral, SSC-Lasso, SSC-OMP, Hierarchical) - $(date)"
python -u pipeline/02_clustering.py

echo ""
echo "Step 3/9: Envelope and power-law analysis - $(date)"
python -u pipeline/03_envelope_analysis.py

echo ""
echo "Step 4/9: Quanta fingerprint (AI detection, GPU) - $(date)"
# Run the 3 methods used in paper tables (Spectral, SSC-Lasso, Hierarchical).
# SSC-OMP is excluded: not in fingerprint/robustness/BoW tables, saves ~22 h.
python -u pipeline/05_fingerprint.py --cluster-method spectral
python -u pipeline/05_fingerprint.py --cluster-method ssc-lasso
python -u pipeline/05_fingerprint.py --cluster-method hierarchical

echo ""
echo "Step 5/9: Taxonomy and feature selection - $(date)"
python -u pipeline/04_taxonomy_categories.py

echo ""
echo "Step 6/9: Per-cluster token taxonomy (Spectral, SSC-Lasso, Hierarchical) - $(date)"
python -u pipeline/09_quanta_taxonomy.py

echo ""
echo "Step 7a/9: Bootstrap stability - SSC-Lasso (50 iterations) - $(date)"
BOOT_N_JOBS=${BOOT_N_JOBS:-20} BOOT_N_ITER=${BOOT_N_ITER:-50} python -u pipeline/06_bootstrap_stability.py

echo ""
echo "Step 7b/9: Bootstrap stability - Spectral and Hierarchical - $(date)"
python -u pipeline/06b_bootstrap_spectral_hierarchical.py --method spectral
python -u pipeline/06b_bootstrap_spectral_hierarchical.py --method hierarchical

echo ""
echo "Step 8/9: Fingerprint robustness (Table 5 / Appendix C) - $(date)"
python -u pipeline/07_fingerprint_robustness.py \
    --fp-subdir quanta_fingerprint_ssc-lasso --paradigm SSC-Lasso
python -u pipeline/07_fingerprint_robustness.py \
    --fp-subdir quanta_fingerprint --paradigm Spectral
python -u pipeline/07_fingerprint_robustness.py \
    --fp-subdir quanta_fingerprint_hierarchical --paradigm Hierarchical

echo ""
echo "Step 9/9: Bag-of-words baseline - $(date)"
python -u pipeline/08_bow_baseline.py

echo ""
echo "Per-model pipeline complete (9/9 steps): $MODEL (finished $(date))"
python -c "from config import PATHS; print(f'  Results: {PATHS[\"results_dir\"]}/')"

if [ "$MODEL" = "pythia-19m" ]; then
    echo ""
    echo "Next: bash run_full_pipeline.sh pythia-125m"
    echo "Then: bash run_cross_model.sh  (taxonomy mirror + all publication figures)"
fi
